from difflib import SequenceMatcher
def seq_ratio(a,b):
    return SequenceMatcher(None,a,b).ratio()

def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    if not atoks or not btoks:
        return 0.0
    set_a = atoks # duplicates matter? use counts
    # compute token overlap with counts
    from collections import Counter
    ca = Counter(atoks)
    cb = Counter(btoks)
    overlap = 0
    for tok in ca:
        overlap += min(ca[tok], cb.get(tok,0))
    if overlap==0:
        return 0.0
    precision = overlap / sum(ca.values())
    recall = overlap / sum(cb.values())
    if precision+recall==0:
        return 0.0
    return 2*precision*recall/(precision+recall)

